        await File.WriteAllTextAsync(Path.Combine(dir, "a.txt"), "x");
        await File.WriteAllTextAsync(Path.Combine(dir, "nested", "b.txt"), "x");

        service.Delete("dir");

        Assert.False(Directory.Exists(dir));
